const rawInput = $input.first().json;
const input = (rawInput.body && typeof rawInput.body === 'object') ? rawInput.body : rawInput;
const searchParams = {
  q: `site:linkedin.com/in/ "${input.keyword}" "${input.city}"`,
  num: Math.min(input.limit || 10, 25)
};
return [{ json: { ...input, serper_search_params: searchParams } }];

const webhookRaw = $('On Webhook Trigger').first().json;
const webhook = (webhookRaw.body && typeof webhookRaw.body === 'object') ? webhookRaw.body : webhookRaw;

const results = $input.first().json.organic || [];
const leadSourceId = webhook.lead_source_id || null;

const leads = results.map(p => {
  const isCompany = p.link && p.link.includes('/company/');
  let firstName = 'Unknown';
  let lastName = '';
  let companyName = '';
  let jobTitle = '';

  if (isCompany) {
    companyName = (p.title || '').replace(' | LinkedIn', '').replace(' - LinkedIn', '').trim();
    firstName = 'Company';
  } else {
    const titleParts = (p.title || '').replace(' | LinkedIn', '').replace(' - LinkedIn', '').split(' - ');
    const name = titleParts[0] ? titleParts[0].trim() : 'Unknown';
    const nameParts = name.split(' ');
    firstName = nameParts[0] || 'Unknown';
    lastName = nameParts.slice(1).join(' ') || '';

    jobTitle = titleParts[1] ? titleParts[1].trim() : '';
    // Use empty string instead of 'Unknown Company' to prevent merging unrelated leads in backend
    companyName = titleParts.length > 2 ? titleParts.slice(2).join(' ').trim() : titleParts.length === 2 && !titleParts[1].includes(' at ') && !titleParts[1].toLowerCase().includes('freelance') ? titleParts[1].trim() : '';
  }

  return {
    first_name: firstName,
    last_name: lastName,
    company_name: companyName,
    email: '',
    phone: '',
    job_title: jobTitle,
    city: webhook.city || '',
    province: '',
    lead_source_id: leadSourceId,
    estimated_value: 0,
    // Use LinkedIn URL as place_id to guarantee unique deduplication per person
    place_id: p.link || '',
    website: p.link || '',
    notes: [
      `Source: LinkedIn via Serper Google Search`,
      `LinkedIn URL: ${p.link || 'N/A'}`,
      `Headline/Snippet: ${p.snippet || 'N/A'}`,
      `Keyword: ${webhook.keyword}`
    ].join('\n')
  };
});

return [{ json: { leads: leads, source: 'linkedin' } }];

// Map Serper Google Maps results directly to GIMS Lead interface
// Serper output is already structured — no AI needed
const webhookRaw = $('On Webhook Trigger').first().json;
// n8n Webhook typeVersion 2 wraps payload under .body
const webhook = (webhookRaw.body && typeof webhookRaw.body === 'object') ? webhookRaw.body : webhookRaw;

const places = $input.first().json.places || [];
const leadSourceId = webhook.lead_source_id || null;
const limit = Math.min(webhook.limit || 10, 20);

const leads = places.slice(0, limit).map(place => {
  // Split business name: first word = first_name, rest = last_name
  const rawTitle = place.title || '';
  const nameParts = rawTitle.split(' ');
  const firstName = nameParts[0] || '';
  const lastName = nameParts.slice(1).join(' ') || '';

  // Extract city and province from comma-separated address
  const addressParts = (place.address || '').split(',').map(s => s.trim());
  let city = webhook.city || '';
  let province = '';

  if (addressParts.length > 0) {
    if (addressParts[addressParts.length - 1].toLowerCase() === 'indonesia') {
      if (addressParts.length >= 3) {
        city = addressParts[addressParts.length - 3].replace(/^(Kota|Kabupaten)\s+/i, '').trim();
        province = addressParts[addressParts.length - 2].replace(/\d+$/, '').trim();
      } else if (addressParts.length === 2) {
        province = addressParts[0].replace(/\d+$/, '').trim();
      }
    } else {
      if (addressParts.length >= 2) {
        city = addressParts[addressParts.length - 2].replace(/^(Kota|Kabupaten)\s+/i, '').trim();
        province = addressParts[addressParts.length - 1].replace(/\d+$/, '').trim();
      } else if (addressParts.length === 1) {
        province = addressParts[0].replace(/\d+$/, '').trim();
      }
    }
  }

  // Derive email from website domain when available
  let email = '';
  if (place.website) {
    try {
      const domain = new URL(place.website).hostname.replace('www.', '');
      email = 'info@' + domain;
    } catch(e) { /* skip malformed URL */ }
  }

  return {
    first_name: firstName,
    last_name: lastName,
    company_name: rawTitle,
    email: email,
    phone: place.phoneNumber || place.phone || '',
    job_title: place.type || (place.types && place.types[0]) || '',
    address: place.address || '',
    city: city,
    province: province,
    lead_source_id: leadSourceId,
    estimated_value: 0,
    // Map Serper link to place_id for clickable UI
    place_id: place.link || '',
    website: place.website || '',
    notes: [
      `Source: Google Maps`,
      `Rating: ${place.rating || 'N/A'} (${place.ratingCount || 0} reviews)`,
      `Category: ${place.type || 'N/A'}`,
      `Website: ${place.website || 'N/A'}`,
      `CID: ${place.cid || 'N/A'}`,
      `Place ID: ${place.placeId || 'N/A'}`,
      `Keyword: ${webhook.keyword}`,
      `Scraped: ${new Date().toISOString()}`
    ].join('\n')
  };
});

return [{ json: { leads: leads, source: 'google_maps' } }];
